public boolean isUnixSymlink() {
    return (getUnixMode() & UnixStat.FILE_TYPE_FLAG) == UnixStat.LINK_FLAG;
}

additional_testcases.testcase:
@Test
public void isUnixSymlinkIsTrueWhenOnlySymlinkFlagIsSet() throws Exception {
    ZipArchiveEntry ze = new ZipArchiveEntry("test");
    ze.setUnixMode(UnixStat.LINK_FLAG);
    assertTrue(ze.isUnixSymlink());
}

@Test
public void isUnixSymlinkIsFalseForRegularFile() throws Exception {
    ZipArchiveEntry ze = new ZipArchiveEntry("test");
    ze.setUnixMode(UnixStat.FILE_FLAG | 0644);
    assertFalse(ze.isUnixSymlink());
}

@Test
public void isUnixSymlinkIsFalseForDirectory() throws Exception {
    ZipArchiveEntry ze = new ZipArchiveEntry("test");
    ze.setUnixMode(UnixStat.DIR_FLAG | 0755);
    assertFalse(ze.isUnixSymlink());
}
